-- 3. Activer tout CXS + taguer workwear
UPDATE products SET exclu = false, actif = true, style = 'classique'
WHERE LOWER(nom) LIKE '%cxs%' OR fournisseur = 'cxs';

-- Vérification
SELECT 
  COUNT(*) FILTER (WHERE actif = true) AS actifs,
  COUNT(*) FILTER (WHERE exclu = true) AS exclus,
  COUNT(*) FILTER (WHERE style = ''classique'') AS workwear,
  COUNT(*) AS total
FROM products;

